class Solution {
public:
    int binaryGap(int n) {
        int maxGap = 0, prevBitPos = -1;
        while (n) {
            int bitPos = n & 1;
            n >>= 1;
            if (bitPos) {
                maxGap = max(maxGap, prevBitPos + 1);
                prevBitPos = bitPos;
            }
        }
        return maxGap;
    }
};
